def _session_to_response(
    row: dict,
    *,
    agent_count: int = 0,
    agent_states: list[str | None] | None = None,
) -> SessionResponse:
    """Convert a claude_sessions row to a normalized SessionResponse."""
    session_state = derive_state(
        row.get("last_event") or "",
        tool_name=row.get("last_tool") or "",
    )
    effective = compute_effective_state(session_state, agent_states or [])
    return SessionResponse(
        session_id=row["session_id"],
        platform="claude",
        pid=row["pid"],
        cwd=row["cwd"],
        entrypoint=row["entrypoint"],
        started_at=row["started_at"],
        last_event=row.get("last_event"),
        last_tool=row.get("last_tool"),
        last_event_at=row.get("last_event_at"),
        pid_alive=bool(row.get("pid_alive", 1)),
        ended_at=row.get("ended_at"),
        branch=row.get("branch", ""),
        source_system=row.get("source_system", ""),
        agent_count=agent_count,
        derived_state=effective,
    )


def _agent_to_response(row: dict) -> AgentResponse:
    """Convert a claude_agents row to a normalized AgentResponse."""
    state = derive_state(
        row.get("last_event") or "",
        tool_name=row.get("last_tool") or "",
        agent_id=row["agent_id"],
    )
    return AgentResponse(
        agent_id=row["agent_id"],
        session_id=row["session_id"],
        platform="claude",
        agent_type=row.get("agent_type", ""),
        last_event=row.get("last_event"),
        last_tool=row.get("last_tool"),
        last_event_at=row.get("last_event_at"),
        started_at=row.get("started_at"),
        ended_at=row.get("ended_at"),
        derived_state=state,
    )


@router.get("/sessions")
async def list_sessions(
    *,
    active: bool | None = None,
) -> list[SessionResponse]:
    """List all sessions across platforms."""
    db = await get_db()
    rows = await schema.get_all_sessions(db, active=active)

    results: list[SessionResponse] = []
    for row in rows:
        agents = await schema.get_session_agents(db, session_id=row["session_id"])
        active_agents = [a for a in agents if a.get("ended_at") is None]
        agent_states = [
            derive_state(
                a.get("last_event") or "",
                tool_name=a.get("last_tool") or "",
                agent_id=a["agent_id"],
            )
            for a in active_agents
        ]
        results.append(
            _session_to_response(
                row,
                agent_count=len(active_agents),
                agent_states=agent_states,
            )
        )
    return results


@router.get("/sessions/{session_id}")
async def get_session(session_id: str) -> SessionDetailResponse:
    """Get a single session with embedded agents."""
    db = await get_db()
    row = await schema.get_session(db, session_id=session_id)
    if row is None:
        raise HTTPException(status_code=404, detail="Session not found")

    agents = await schema.get_session_agents(db, session_id=session_id)
    active_agents = [a for a in agents if a.get("ended_at") is None]
    agent_states = [
        derive_state(
            a.get("last_event") or "",
            tool_name=a.get("last_tool") or "",
            agent_id=a["agent_id"],
        )
        for a in active_agents
    ]
    session_state = derive_state(
        row.get("last_event") or "",
        tool_name=row.get("last_tool") or "",
    )
    effective = compute_effective_state(session_state, agent_states)

    agent_responses = [_agent_to_response(a) for a in agents]

    return SessionDetailResponse(
        session_id=row["session_id"],
        platform="claude",
        pid=row["pid"],
        cwd=row["cwd"],
        entrypoint=row["entrypoint"],
        started_at=row["started_at"],
        last_event=row.get("last_event"),
        last_tool=row.get("last_tool"),
        last_event_at=row.get("last_event_at"),
        pid_alive=bool(row.get("pid_alive", 1)),
        ended_at=row.get("ended_at"),
        branch=row.get("branch", ""),
        source_system=row.get("source_system", ""),
        agent_count=len(active_agents),
        derived_state=effective,
        agents=agent_responses,
    )


@router.post("/sessions/{session_id}/clear")
async def clear_session(session_id: str) -> dict:
    """Clear session state as if freshly connected.

    Resets last_event/last_tool/last_event_at, ends all active agents,
    and writes a synthetic clear_state marker event.
    """
    db = await get_db()
    row = await schema.get_session(db, session_id=session_id)
    if row is None:
        raise HTTPException(status_code=404, detail="Session not found")

    import time

    cleared_at = time.time()
    await schema.clear_session(db, session_id=session_id, cleared_at=cleared_at)
    await schema.insert_event(
        db,
        session_id=session_id,
        event_name="clear_state",
        received_at=cleared_at,
        raw_payload="{}",
    )

    from agentpulse.websocket import manager

    await manager.broadcast(
        {
            "type": "session_cleared",
            "platform": "claude",
            "session_id": session_id,
            "event_name": "clear_state",
            "tool_name": None,
            "agent_id": None,
            "cwd": row.get("cwd"),
            "timestamp": cleared_at,
        }
    )

    return {"status": "cleared", "session_id": session_id}


